// Pull email + existing GHL Contact ID off the current task
const task = $input.item.json;
const customFields = task.custom_fields || [];

const EMAIL_FIELD_ID = '6b7de2eb-ac4f-4880-b8d6-59bad0998df4';
const GHL_ID_FIELD_ID = 'cd9f064c-c9d0-4bd2-976c-86e41a86350c';

const emailField = customFields.find(f => f.id === EMAIL_FIELD_ID);
const ghlIdField = customFields.find(f => f.id === GHL_ID_FIELD_ID);

const email = (emailField && emailField.value ? String(emailField.value) : '').trim().toLowerCase();
const existingGhlId = (ghlIdField && ghlIdField.value ? String(ghlIdField.value) : '').trim();

const hasEmail = email.length > 0;
const hasGhlId = existingGhlId.length > 0;
const shouldProcess = hasEmail && !hasGhlId;

return [{
  json: {
    taskId: task.id,
    taskName: task.name,
    email,
    existingGhlId,
    hasEmail,
    hasGhlId,
    shouldProcess,
  }
}];

// Carry the email/taskId from the upstream Extract node and pick the first exact-email match
const upstream = $('Extract Email & GHL ID').item.json;
const search = $input.item.json || {};
const rawContacts = search.contacts || search.data || [];

const targetEmail = (upstream.email || '').toLowerCase();
const exactMatches = rawContacts.filter(c => {
  const candidate = (c.email || c.emailLowerCase || '').toString().toLowerCase();
  return candidate === targetEmail;
});

const chosen = exactMatches[0] || null;
const foundContact = !!chosen;
const multipleMatches = exactMatches.length > 1;

return [{
  json: {
    taskId: upstream.taskId,
    taskName: upstream.taskName,
    email: upstream.email,
    foundContact,
    multipleMatches,
    matchCount: exactMatches.length,
    ghlContactId: chosen ? (chosen.id || chosen.contactId) : '',
    ghlContactName: chosen ? (chosen.contactName || `${chosen.firstName || ''} ${chosen.lastName || ''}`.trim()) : '',
  }
}];
